from datetime import datetime, timezone
import json
from pathlib import Path

def knowledge_base_health_report(
    source_ids: list[str],
    lineage_log: str,
    collection,
    month: str,  # "2025-06"
) -> dict:
    metrics = {}
    for src in source_ids:
        chunks = collection.get(where={"source_id": src}, include=["metadatas"])
        if not chunks["ids"]:
            metrics[src] = {"status": "MISSING", "chunk_count": 0}
            continue

        # Freshness: check ingest_timestamp of most recent chunk
        timestamps = [m.get("ingest_timestamp", "") for m in chunks["metadatas"]]
        latest = max(timestamps) if timestamps else ""
        metrics[src] = {
            "chunk_count": len(chunks["ids"]),
            "latest_ingest": latest,
            "status": "OK",
        }

    # Retrieval usage from lineage log
    retrieval_counts: dict[str, int] = {}
    for line in Path(lineage_log).read_text().splitlines():
        span = json.loads(line)
        if (span.get("name") == "claude.rag_retrieval"
                and span.get("start_time", "").startswith(month)):
            for sid in span.get("attributes", {}).get("claude.rag.source_ids", []):
                retrieval_counts[sid] = retrieval_counts.get(sid, 0) + 1

    return {
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "month": month,
        "source_metrics": metrics,
        "retrieval_distribution": retrieval_counts,
    }
